import{_ as s,c as a,o as n,d as l}from"./app.6cd4b0b7.js";const u=JSON.parse('{"title":"docker部署的springboot应用flowable流程图乱码","description":"docker、springboot、flowable","frontmatter":{"title":"docker部署的springboot应用flowable流程图乱码","description":"docker、springboot、flowable","date":"2022-08-09T00:00:00.000Z","category":"Bug","tags":["docker","flowable"]},"headers":[{"level":3,"title":"docker部署的flowable流程图乱码","slug":"docker部署的flowable流程图乱码","link":"#docker部署的flowable流程图乱码","children":[]}],"relativePath":"posts/docker下flowable流程图乱码.md","lastUpdated":1673337321000}'),e={name:"posts/docker下flowable流程图乱码.md"},p=l(`<h3 id="docker部署的flowable流程图乱码" tabindex="-1">docker部署的flowable流程图乱码 <a class="header-anchor" href="#docker部署的flowable流程图乱码" aria-hidden="true">#</a></h3><p>原因：构建镜像使用的jdk没有需要的字体</p><p>将需要的字体提取，重新构建jdk镜像即可</p><p>docker 查看容器的长id</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-palenight"><code><span class="line"><span style="color:#FFCB6B;">docker</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">inspect</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-f</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">{{.ID}}</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">短id</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>docker复制文件至容器内</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-palenight"><code><span class="line"><span style="color:#FFCB6B;">docker</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">cp</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">本地路径</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">容器长ID:容器路径</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>将Windows下 C:\\Windows\\Fonts下的字体文件提取</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-palenight"><code><span class="line"><span style="color:#A6ACCD;">simsun.ttc 宋体常规</span></span>
<span class="line"><span style="color:#A6ACCD;">simhei.ttf 黑体常规</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-palenight"><code><span class="line"><span style="color:#A6ACCD;">#依赖镜像名称和ID</span></span>
<span class="line"><span style="color:#A6ACCD;">FROM centos:7</span></span>
<span class="line"><span style="color:#A6ACCD;">#指定镜像创建者信息</span></span>
<span class="line"><span style="color:#A6ACCD;">MAINTAINER admin</span></span>
<span class="line"><span style="color:#A6ACCD;">#切换工作目录</span></span>
<span class="line"><span style="color:#A6ACCD;">WORKDIR /usr</span></span>
<span class="line"><span style="color:#A6ACCD;">RUN mkdir /usr/local/java</span></span>
<span class="line"><span style="color:#A6ACCD;">#ADD 是相对路径jar,把java添加到容器中</span></span>
<span class="line"><span style="color:#A6ACCD;">ADD jdk-8u333-linux-x64.tar.gz /usr/local/java/</span></span>
<span class="line"><span style="color:#A6ACCD;">ADD simsun.ttc /usr/local/java/jdk1.8.0_333/jre/lib/fonts</span></span>
<span class="line"><span style="color:#A6ACCD;">ADD simhei.ttf /usr/local/java/jdk1.8.0_333/jre/lib/fonts</span></span>
<span class="line"><span style="color:#A6ACCD;">#配置java环境变量</span></span>
<span class="line"><span style="color:#A6ACCD;">ENV JAVA_HOME /usr/local/java/jdk1.8.0_333</span></span>
<span class="line"><span style="color:#A6ACCD;">ENV JRE_HOME $JAVA_HOME/jre</span></span>
<span class="line"><span style="color:#A6ACCD;">ENV CLASSPATH $JAVA_HOME/lib/dt.jar:$JAVA_HOME/lib/tools.jar:$JRE_HOME/lib:$CLASSPATH</span></span>
<span class="line"><span style="color:#A6ACCD;">ENV PATH $JAVA_HOME/bin:$PATH</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div>`,10),o=[p];function r(c,i,t,d,b,A){return n(),a("div",null,o)}const D=s(e,[["render",r]]);export{u as __pageData,D as default};
